import axios from "axios";

// Create axios instance with base URL
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:5000/api",
  headers: { "Content-Type": "application/json" },
});

// Request interceptor: attach JWT if available
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("nfxtoken");
    if (token) {
      // Set Authorization: Bearer <token>
      config.headers = config.headers || {};
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response interceptor: keep 401/403 visible to callers, optional global handling
api.interceptors.response.use(
  (res) => res,
  (err) => {
    // Do not swallow the error: allow per-call catch to see status & data
    return Promise.reject(err);
  }
);

// -------- AUTH --------
export const loginUser = async ({ email, password }) => {
  const response = await api.post("/auth/login", { email, password });
  if (response?.data?.token) {
    localStorage.setItem("nfxtoken", response.data.token);
  }
  return response.data;
};

export const signupUser = async ({ name, email, password }) => {
  const response = await api.post("/auth/register", { name, email, password });
  return response.data;
};

export const logoutUser = () => {
  localStorage.removeItem("nfxtoken");
};

// -------- VEHICLES --------
export const listVehicles = async () => {
  const res = await api.get("/vehicles");
  return res.data;
};

export const createVehicle = async (payload) => {
  // payload example: { license_plate: "KA-01-AB-1234", status: "active" }
  const res = await api.post("/vehicles", payload);
  return res.data;
};

export default api;
